16		// Import the configinit package for its init() side-effect: it triggers
17		// agent's internal/config init which registers the config loader into
18		// agentlib so that agentlib.New(ServiceOptions{ConfigPath:…}) can resolve
19		// provider configuration without a separate adapter. configinit is the
20		// public marker package exposed for this purpose after agent v0.5.0
21		// moved internal/config out of the public surface.
22		_ "github.com/DocumentDrivenDX/agent/configinit"
23		ddxconfig "github.com/DocumentDrivenDX/ddx/internal/config"
