26	// DefaultProviderRequestTimeout bounds a single Chat / ChatStream call.
27	// Defeats RC4 of ddx-0a651925: a stalled TCP socket that has delivered
28	// headers but stopped emitting body bytes would otherwise pin a goroutine
29	// until the outer wall-clock (3h) frees it.
30	const DefaultProviderRequestTimeout = 15 * time.Minute
31	
32	// DefaultProviderIdleReadTimeout bounds the maximum idle gap between stream
33	// deltas. Used by service callers to bound idle reads on streaming providers.
34	const DefaultProviderIdleReadTimeout = 5 * time.Minute
