36	// NewServiceFromWorkDir constructs a DdxAgent for the given DDx project.
37	// When .ddx/config.yaml contains agent.endpoints, those endpoint blocks are
38	// injected as the service config so routing is independent from global named
39	// provider profiles. Otherwise, ConfigPath preserves the upstream agent loader
40	// fallback for legacy .agent/global configuration.
41	func NewServiceFromWorkDir(workDir string) (agentlib.DdxAgent, error) {
42		opts := agentlib.ServiceOptions{
43			ConfigPath: filepath.Join(workDir, "config.yaml"),
44		}
45		sc, err := serviceConfigFromDDxEndpoints(workDir)
46		if err != nil {
47			return nil, err
48		}
49		if sc != nil {
50			opts.ServiceConfig = sc
51		}
52		return agentlib.New(opts)
53	}
54	
55	// NewStatusProbeServiceFromWorkDir constructs a service for status surfaces
56	// without pre-filtering .ddx agent endpoints by /models reachability. The
57	// returned service still probes when ListProviders is called, but unreachable
58	// configured endpoints remain present in the result as unreachable rows.
59	func NewStatusProbeServiceFromWorkDir(workDir string) (agentlib.DdxAgent, error) {
60		opts := agentlib.ServiceOptions{
61			ConfigPath: filepath.Join(workDir, "config.yaml"),
62		}
63		sc, err := serviceConfigFromDDxEndpointsNoFilter(workDir)
64		if err != nil {
65			return nil, err
66		}
67		if sc != nil {
68			opts.ServiceConfig = sc
69		}
70		return agentlib.New(opts)
71	}
