80	func serviceConfigFromDDxEndpoints(workDir string) (agentlib.ServiceConfig, error) {
81		cfg, err := ddxconfig.LoadWithWorkingDir(workDir)
82		if err != nil {
83			return nil, err
84		}
85		if cfg.Agent == nil || len(cfg.Agent.Endpoints) == 0 {
86			return nil, nil
87		}
88		return newEndpointServiceConfig(context.Background(), cfg.Agent.Endpoints, workDir)
89	}
