91	func serviceConfigFromDDxEndpointsNoFilter(workDir string) (agentlib.ServiceConfig, error) {
92		cfg, err := ddxconfig.LoadWithWorkingDir(workDir)
93		if err != nil {
94			return nil, err
95		}
96		if cfg.Agent == nil || len(cfg.Agent.Endpoints) == 0 {
97			return nil, nil
98		}
99		return newEndpointServiceConfigWithoutLiveFilter(cfg.Agent.Endpoints, workDir)
100	}
