102	// ConfiguredProviderSnapshots returns endpoint-provider rows from .ddx config
103	// without probing their /models endpoints. It is used by UI surfaces that must
104	// first-paint from last-known or configured state and refresh live probes
105	// asynchronously.
106	func ConfiguredProviderSnapshots(workDir string) ([]agentlib.ProviderInfo, bool, error) {
107		cfg, err := ddxconfig.LoadWithWorkingDir(workDir)
108		if err != nil {
109			return nil, false, err
110		}
111		if cfg.Agent == nil || len(cfg.Agent.Endpoints) == 0 {
112			return nil, false, nil
113		}
114		out := make([]agentlib.ProviderInfo, 0, len(cfg.Agent.Endpoints))
115		for i, endpoint := range cfg.Agent.Endpoints {
116			name, entry, err := endpointProviderEntry(endpoint, i)
117			if err != nil {
118				return nil, true, err
119			}
120			out = append(out, agentlib.ProviderInfo{
121				Name:         name,
122				Type:         strings.ToLower(strings.TrimSpace(entry.Type)),
123				BaseURL:      entry.BaseURL,
124				Endpoints:    append([]agentlib.ServiceProviderEndpoint(nil), entry.Endpoints...),
125				Status:       "unknown",
126				DefaultModel: entry.Model,
127				IsDefault:    i == 0,
128			})
129		}
130		return out, true, nil
131	}
