133	func newEndpointServiceConfig(ctx context.Context, endpoints []ddxconfig.AgentEndpoint, workDir string) (*endpointServiceConfig, error) {
134		sc := &endpointServiceConfig{
135			providers: make(map[string]agentlib.ServiceProviderEntry),
136			workDir:   workDir,
137		}
138		for i, endpoint := range endpoints {
139			name, entry, err := endpointProviderEntry(endpoint, i)
140			if err != nil {
141				return nil, err
142			}
143			if !endpointHasLiveModels(ctx, entry.BaseURL, entry.APIKey) {
144				continue
145			}
146			sc.providers[name] = entry
147			sc.names = append(sc.names, name)
148			if sc.defaultName == "" {
149				sc.defaultName = name
150			}
151		}
152		return sc, nil
153	}
