155	func newEndpointServiceConfigWithoutLiveFilter(endpoints []ddxconfig.AgentEndpoint, workDir string) (*endpointServiceConfig, error) {
156		sc := &endpointServiceConfig{
157			providers: make(map[string]agentlib.ServiceProviderEntry),
158			workDir:   workDir,
159		}
160		for i, endpoint := range endpoints {
161			name, entry, err := endpointProviderEntry(endpoint, i)
162			if err != nil {
163				return nil, err
164			}
165			sc.providers[name] = entry
166			sc.names = append(sc.names, name)
167			if sc.defaultName == "" {
168				sc.defaultName = name
169			}
170		}
171		return sc, nil
172	}
