174	func endpointProviderEntry(endpoint ddxconfig.AgentEndpoint, index int) (string, agentlib.ServiceProviderEntry, error) {
175		providerType := strings.ToLower(strings.TrimSpace(endpoint.Type))
176		baseURL := strings.TrimSpace(endpoint.BaseURL)
177		if baseURL == "" {
178			if endpoint.Host == "" || endpoint.Port == 0 {
179				return "", agentlib.ServiceProviderEntry{}, fmt.Errorf("agent.endpoints[%d]: base_url or host+port is required", index)
180			}
181			baseURL = fmt.Sprintf("http://%s:%d/v1", endpoint.Host, endpoint.Port)
182		}
183		if providerType == "" {
184			providerType = inferEndpointProviderType(baseURL, endpoint.Port)
185		}
186		if providerType == "" {
187			return "", agentlib.ServiceProviderEntry{}, fmt.Errorf("agent.endpoints[%d]: type is required when it cannot be inferred", index)
188		}
189	
190		name := endpointProviderName(providerType, baseURL, endpoint, index)
191		return name, agentlib.ServiceProviderEntry{
192			Type:    providerType,
193			BaseURL: baseURL,
194			APIKey:  endpoint.APIKey,
195		}, nil
196	}
