198	func inferEndpointProviderType(baseURL string, port int) string {
199		low := strings.ToLower(baseURL)
200		switch {
201		case strings.Contains(low, "openrouter.ai"):
202			return "openrouter"
203		case strings.Contains(low, "openai.com"):
204			return "openai"
205		case strings.Contains(low, ":1235") || port == 1235:
206			return "omlx"
207		case strings.Contains(low, ":11434") || port == 11434:
208			return "ollama"
209		case strings.Contains(low, ":1234") || port == 1234:
210			return "lmstudio"
211		default:
212			return ""
213		}
214	}
