216	func endpointProviderName(providerType, baseURL string, endpoint ddxconfig.AgentEndpoint, index int) string {
217		host := endpoint.Host
218		port := endpoint.Port
219		if u, err := url.Parse(baseURL); err == nil {
220			if host == "" {
221				host = u.Hostname()
222			}
223			if port == 0 {
224				if p := u.Port(); p != "" {
225					if n, err := strconv.Atoi(p); err == nil {
226						port = n
227					}
228				}
229			}
230		}
231		parts := []string{providerType}
232		if host != "" {
233			parts = append(parts, host)
234		}
235		if port != 0 {
236			parts = append(parts, strconv.Itoa(port))
237		}
238		if len(parts) == 1 {
239			parts = append(parts, strconv.Itoa(index+1))
240		}
241		return sanitizeEndpointName(strings.Join(parts, "-"))
242	}
243	
244	func sanitizeEndpointName(s string) string {
245		s = strings.ToLower(strings.TrimSpace(s))
246		var b strings.Builder
247		lastDash := false
248		for _, r := range s {
249			keep := unicode.IsLetter(r) || unicode.IsDigit(r)
250			if keep {
251				b.WriteRune(r)
252				lastDash = false
253				continue
254			}
255			if !lastDash {
256				b.WriteByte('-')
257				lastDash = true
258			}
259		}
260		out := strings.Trim(b.String(), "-")
261		if out == "" {
262			return "endpoint"
263		}
264		return out
265	}
