267	func endpointHasLiveModels(ctx context.Context, baseURL, apiKey string) bool {
268		probeCtx, cancel := context.WithTimeout(ctx, 2*time.Second)
269		defer cancel()
270	
271		req, err := http.NewRequestWithContext(probeCtx, http.MethodGet, strings.TrimRight(baseURL, "/")+"/models", nil)
272		if err != nil {
273			return false
274		}
275		if apiKey != "" {
276			req.Header.Set("Authorization", "Bearer "+apiKey)
277		}
278		resp, err := http.DefaultClient.Do(req)
279		if err != nil {
280			return false
281		}
282		defer resp.Body.Close() //nolint:errcheck
283		if resp.StatusCode < 200 || resp.StatusCode >= 300 {
284			return false
285		}
286	
287		var payload struct {
288			Data []struct {
289				ID string `json:"id"`
290			} `json:"data"`
291		}
292		if err := json.NewDecoder(resp.Body).Decode(&payload); err != nil {
293			return false
294		}
295		for _, model := range payload.Data {
296			if strings.TrimSpace(model.ID) != "" {
297				return true
298			}
299		}
300		return false
301	}
