1	package agent
2	
3	import (
4		"context"
5		"encoding/json"
6		"fmt"
7		"os"
8		"time"
9	
10		agentlib "github.com/DocumentDrivenDX/agent"
11	)
12	
13	// Public event-type strings emitted by agentlib.DdxAgent.Execute, mirrored
14	// from CONTRACT-003 §"Event JSON shapes". Kept as constants here so the
15	// drain loop does not have to import the agent's internal/harnesses
16	// package (which is module-private).
17	const (
18		serviceEventRoutingDecision = "routing_decision"
19		serviceEventTextDelta       = "text_delta"
20		serviceEventToolCall        = "tool_call"
21		serviceEventToolResult      = "tool_result"
22		serviceEventStall           = "stall"
23		serviceEventFinal           = "final"
24		serviceEventCompaction      = "compaction"
25		serviceEventCompactionEnd   = "compaction.end"
26	)
27	
28	const (
29		serviceNoopCompactionWallClockLimit  = 15 * time.Minute
30		serviceNoopCompactionWallClockReason = "compaction_stuck_wall_clock_timeout"
31	)
32	
33	// ServiceEvent payload types are now aliases to the upstream v0.8.0 public
34	// types (agent-f0bc5467). DDx previously maintained byte-for-byte shadow
35	// copies of these structs because CONTRACT-003 hadn't published them; that
36	// left the consumer carrying stream-adjacent knowledge and drifted whenever
37	// upstream shapes changed. With v0.8.0 the types are public and stable.
38	//
39	// Aliases rather than an outright delete so existing call sites keep
40	// working without a sweep. New code can (and should) use agentlib types
41	// directly.
42	type (
43		serviceFinalData      = agentlib.ServiceFinalData
44		serviceFinalUsage     = agentlib.ServiceFinalUsage
45		serviceRoutingActual  = agentlib.ServiceRoutingActual
46		serviceToolCallData   = agentlib.ServiceToolCallData
47		serviceToolResultData = agentlib.ServiceToolResultData
48	)
49	
50	// useNewAgentPath reports whether RunAgent should dispatch to the new
51	// agentlib.DdxAgent.Execute path. Default is on. Set the env var
52	// DDX_USE_NEW_AGENT_PATH=0 (or "false") to disable as an emergency escape
53	// hatch.
54	func useNewAgentPath() bool {
55		switch os.Getenv("DDX_USE_NEW_AGENT_PATH") {
56		case "0", "false", "FALSE", "False":
57			return false
58		default:
59			return true
60		}
61	}
62	
63	// runAgentViaService is the new RunAgent dispatch path that drives the
64	// agent through agentlib.DdxAgent.Execute and drains the resulting event
65	// channel into a DDx Result. Old in-package code paths (RunAgent legacy
66	// loop, embeddedCompactionConfig, buildAgentProvider, findTool,
67	// wrapProviderWithDeadlines, stall + compaction-stuck circuit breakers)
68	// stay in place; this function does NOT call them.
69	//
70	// Stall detection: we delegate to the agent's StallPolicy. The agent
71	// emits a stall event then a final event with Status="stalled".
72	func runAgentViaService(r *Runner, opts RunArgs) (*Result, error) {
73		promptText, err := r.resolvePrompt(opts)
74		if err != nil {
75			return nil, err
76		}
77	
78		model := r.resolveModel(opts, "agent")
79		timeout := r.resolveTimeout(opts)
80		wallClock := r.resolveWallClock(opts)
81	
82		wd := opts.WorkDir
83		if wd == "" {
84			wd, _ = os.Getwd()
85		}
86	
87		// Construct the service. Reuses NewServiceFromWorkDir so provider/model
88		// routing data lands on the agent the same way every other DDx command
89		// constructs it (see serviceconfig.go).
90		svc, err := NewServiceFromWorkDir(wd)
91		if err != nil {
92			return nil, fmt.Errorf("agent: build service: %w", err)
93		}
94	
95		// Resolve where to write the per-request session log.
96		logDir := opts.SessionLogDir
97		if logDir == "" {
98			logDir = r.Config.SessionLogDir
99		}
100		if logDir == "" {
101			logDir = DefaultLogDir
102		}
103	
104		// Build the public ExecuteRequest per CONTRACT-003.
105		req := agentlib.ServiceExecuteRequest{
106			Prompt:          promptText,
107			Model:           model,
108			Provider:        opts.Provider,
109			Harness:         "agent",
110			ModelRef:        opts.ModelRef,
111			Reasoning:       agentlib.Reasoning(opts.Effort),
112			Permissions:     opts.Permissions,
113			WorkDir:         wd,
114			Timeout:         wallClock,
115			IdleTimeout:     timeout,
116			ProviderTimeout: DefaultProviderRequestTimeout,
117			SessionLogDir:   logDir,
118			Metadata:        opts.Correlation,
119		}
120	
121		parentCtx := opts.Context
122		if parentCtx == nil {
123			parentCtx = context.Background()
124		}
125		ctx, cancel := context.WithCancel(parentCtx)
126		defer cancel()
127	
128		start := time.Now()
129		events, err := svc.Execute(ctx, req)
130		if err != nil {
131			return nil, fmt.Errorf("agent: execute: %w", err)
132		}
133	
134		final, toolCalls, routing := drainServiceEvents(events)
135		elapsed := time.Since(start)
136	
137		result := &Result{
138			Harness:    "agent",
139			Model:      model,
140			DurationMS: int(elapsed.Milliseconds()),
141			ToolCalls:  toolCalls,
142		}
143		if routing != nil {
144			result.Provider = routing.Provider
145			if routing.Model != "" {
146				result.Model = routing.Model
147			}
148		}
149		if final != nil {
150			// Normalized final text from the upstream harness (agent-32e8ff5e).
151			result.Output = final.FinalText
152			if final.Usage != nil {
153				// v0.9.1: Usage fields became *int so the API can distinguish
154				// "harness reported zero" from "harness didn't report". Treat
155				// nil as zero for DDx's int-valued result struct.
156				if final.Usage.InputTokens != nil {
157					result.InputTokens = *final.Usage.InputTokens
158				}
159				if final.Usage.OutputTokens != nil {
160					result.OutputTokens = *final.Usage.OutputTokens
161				}
162				if final.Usage.TotalTokens != nil {
163					result.Tokens = *final.Usage.TotalTokens
164				}
165			}
166			if final.CostUSD > 0 {
167				result.CostUSD = final.CostUSD
168			}
169			if final.RoutingActual != nil {
170				if result.Provider == "" {
171					result.Provider = final.RoutingActual.Provider
172				}
173				if final.RoutingActual.Model != "" {
174					result.Model = final.RoutingActual.Model
175				}
176			}
177			switch final.Status {
178			case "success", "":
179				// happy path; no-op
180			case "stalled":
181				result.ExitCode = 1
182				if final.Error != "" {
183					result.Error = "stalled: " + final.Error
184				} else {
185					result.Error = "stalled"
186				}
187			case "timed_out":
188				result.ExitCode = 1
189				result.Error = fmt.Sprintf("timeout after %v", wallClock.Round(time.Second))
190			case "cancelled":
191				result.ExitCode = 1
192				result.Error = "cancelled"
193			default:
194				result.ExitCode = 1
195				if final.Error != "" {
196					result.Error = final.Error
197				} else {
198					result.Error = final.Status
199				}
200			}
201			if final.SessionLogPath != "" {
202				// surface as session ID for downstream cross-reference (mirrors
203				// the legacy path's AgentSessionID population).
204				result.AgentSessionID = final.SessionLogPath
205			}
206		}
207	
208		promptSource := opts.PromptSource
209		if promptSource == "" {
210			if opts.PromptFile != "" {
211				promptSource = opts.PromptFile
212			} else {
213				promptSource = "inline"
214			}
215		}
216		r.logSession(result, len(promptText), promptText, promptSource, opts.Correlation)
217		r.recordRoutingOutcome(result, elapsed, opts)
218		return result, nil
219	}
220	
221	// drainServiceEvents reads service events and returns the final-event payload,
222	// the accumulated tool-call log, and the routing decision (when present in the
223	// routing_decision start event). A sustained run of no-op compaction telemetry
224	// is converted into a synthetic stalled final so execute-bead result details
225	// identify the time-based breaker instead of waiting for the outer wall clock.
226	func drainServiceEvents(events <-chan agentlib.ServiceEvent) (*serviceFinalData, []ToolCallEntry, *serviceRoutingActual) {
227		var final *serviceFinalData
228		var routing *serviceRoutingActual
229		var toolCalls []ToolCallEntry
230		pending := make(map[string]*ToolCallEntry) // call_id -> entry awaiting result
231		var noopCompactions serviceNoopCompactionStreak
232		var noopTimer *time.Timer
233		var noopTimerC <-chan time.Time
234		defer func() { stopNoopCompactionTimer(noopTimer) }()
235	
236		for {
237			select {
238			case <-noopTimerC:
239				detail := noopCompactions.detail(serviceNoopCompactionWallClockLimit, serviceNoopCompactionWallClockLimit)
240				return &serviceFinalData{
241					Status: "stalled",
242					Error:  detail,
243				}, toolCallsWithPending(toolCalls, pending), routing
244			case ev, ok := <-events:
245				if !ok {
246					// Any tool_call without a matching tool_result still gets recorded.
247					return final, toolCallsWithPending(toolCalls, pending), routing
248				}
249				if isNoopCompactionEvent(ev) {
250					detail, started := noopCompactions.record(eventTimestamp(ev), serviceNoopCompactionWallClockLimit)
251					if started {
252						noopTimer, noopTimerC = resetNoopCompactionTimer(noopTimer, serviceNoopCompactionWallClockLimit)
253					}
254					if detail != "" {
255						return &serviceFinalData{
256							Status: "stalled",
257							Error:  detail,
258						}, toolCallsWithPending(toolCalls, pending), routing
259					}
260					continue
261				}
262				if isServiceProgressEvent(ev) {
263					noopCompactions.reset()
264					stopNoopCompactionTimer(noopTimer)
265					noopTimerC = nil
266				}
267	
268				switch string(ev.Type) {
269				case serviceEventRoutingDecision:
270					var payload struct {
271						Harness  string `json:"harness"`
272						Provider string `json:"provider"`
273						Model    string `json:"model"`
274					}
275					if err := json.Unmarshal(ev.Data, &payload); err == nil {
276						routing = &serviceRoutingActual{
277							Harness:  payload.Harness,
278							Provider: payload.Provider,
279							Model:    payload.Model,
280						}
281					}
282				case serviceEventToolCall:
283					var data serviceToolCallData
284					if err := json.Unmarshal(ev.Data, &data); err == nil {
285						entry := &ToolCallEntry{
286							Tool:  data.Name,
287							Input: string(data.Input),
288						}
289						pending[data.ID] = entry
290					}
291				case serviceEventToolResult:
292					var data serviceToolResultData
293					if err := json.Unmarshal(ev.Data, &data); err == nil {
294						if entry, ok := pending[data.ID]; ok {
295							entry.Output = data.Output
296							entry.Error = data.Error
297							entry.Duration = int(data.DurationMS)
298							toolCalls = append(toolCalls, *entry)
299							delete(pending, data.ID)
300						}
301					}
302				case serviceEventFinal:
303					var data serviceFinalData
304					if err := json.Unmarshal(ev.Data, &data); err == nil {
305						final = &data
306					}
307				}
308			}
309		}
310	}
311	
312	func resetNoopCompactionTimer(timer *time.Timer, limit time.Duration) (*time.Timer, <-chan time.Time) {
313		if limit <= 0 {
314			return timer, nil
315		}
316		if timer == nil {
317			timer = time.NewTimer(limit)
318			return timer, timer.C
319		}
320		stopNoopCompactionTimer(timer)
321		timer.Reset(limit)
322		return timer, timer.C
323	}
324	
325	func stopNoopCompactionTimer(timer *time.Timer) {
326		if timer == nil {
327			return
328		}
329		if !timer.Stop() {
330			select {
331			case <-timer.C:
332			default:
333			}
334		}
335	}
