337	type serviceNoopCompactionStreak struct {
338		start time.Time
339		count int
340	}
341	
342	func (s *serviceNoopCompactionStreak) record(ts time.Time, limit time.Duration) (string, bool) {
343		if limit <= 0 {
344			return "", false
345		}
346		if ts.IsZero() {
347			ts = time.Now().UTC()
348		}
349		started := false
350		if s.count == 0 {
351			s.start = ts
352			started = true
353		}
354		s.count++
355		elapsed := ts.Sub(s.start)
356		if elapsed < limit {
357			return "", started
358		}
359		return s.detail(elapsed, limit), started
360	}
361	
362	func (s *serviceNoopCompactionStreak) detail(elapsed, limit time.Duration) string {
363		if elapsed < limit {
364			elapsed = limit
365		}
366		return fmt.Sprintf("%s: time-based breaker fired after %s of consecutive no-op compaction events (limit %s, count %d)",
367			serviceNoopCompactionWallClockReason,
368			elapsed.Round(time.Second),
369			limit.Round(time.Second),
370			s.count)
371	}
372	
373	func (s *serviceNoopCompactionStreak) reset() {
374		s.start = time.Time{}
375		s.count = 0
376	}
