75	// executeOnService dispatches against a pre-built svc using the durable
76	// knobs from rcfg and per-invocation plumbing from runtime, then records
77	// one session-index row. It is the inlined replacement for the retired
78	// RunViaServiceWith helper and is shared with dispatchViaResolvedConfig.
79	func executeOnService(ctx context.Context, svc agentlib.DdxAgent, workDir string, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
80		if svc == nil {
81			return nil, fmt.Errorf("agent: nil service")
82		}
83		if ctx == nil {
84			ctx = context.Background()
85		}
86	
87		promptText := runtime.Prompt
88		if runtime.PromptFile != "" {
89			data, err := readPromptFileBounded(runtime.PromptFile)
90			if err != nil {
91				return nil, fmt.Errorf("agent: read prompt file: %w", err)
92			}
93			promptText = string(data)
94		}
95		if promptText == "" {
96			return nil, fmt.Errorf("agent: prompt is required")
97		}
98	
99		wd := runtime.WorkDir
100		if wd == "" {
101			wd = workDir
102		}
103		if wd == "" {
104			wd, _ = os.Getwd()
105		}
106	
107		idle := rcfg.Timeout()
108		if idle <= 0 {
109			idle = time.Duration(DefaultTimeoutMS) * time.Millisecond
110		}
111		wall := rcfg.WallClock()
112		if wall <= 0 {
113			wall = time.Duration(DefaultWallClockMS) * time.Millisecond
114		}
115	
116		sessionLogDir := runtime.SessionLogDirOverride
117		if sessionLogDir == "" {
118			sessionLogDir = rcfg.SessionLogDir()
119		}
120		if sessionLogDir == "" {
121			sessionLogDir = ResolveLogDir(workDir, "")
122		}
123	
124		harness := runtime.HarnessOverride
125		if harness == "" {
126			harness = rcfg.Harness()
127		}
128		if harness == "" && rcfg.Provider() != "" {
129			harness = rcfg.Provider()
130		}
131	
132		model := runtime.ModelOverride
133		if model == "" {
134			model = rcfg.Model()
135		}
136	
137		permissions := runtime.PermissionsOverride
138		if permissions == "" {
139			permissions = rcfg.Permissions()
140		}
141	
142		req := agentlib.ServiceExecuteRequest{
143			Prompt:          promptText,
144			Model:           model,
145			Provider:        rcfg.Provider(),
146			Harness:         harness,
147			ModelRef:        rcfg.ModelRef(),
148			Reasoning:       agentlib.Reasoning(rcfg.Effort()),
149			Permissions:     permissions,
150			WorkDir:         wd,
151			Timeout:         wall,
152			IdleTimeout:     idle,
153			ProviderTimeout: DefaultProviderRequestTimeout,
154			SessionLogDir:   sessionLogDir,
155			Metadata:        runtime.Correlation,
156		}
157	
158		cancelCtx, cancel := context.WithCancel(ctx)
159		defer cancel()
160	
161		start := time.Now().UTC()
162		events, err := svc.Execute(cancelCtx, req)
163		if err != nil {
164			return nil, fmt.Errorf("agent: execute: %w", err)
165		}
166	
167		final, toolCalls, routing := drainServiceEvents(events)
168		finishedAt := time.Now().UTC()
169		elapsed := finishedAt.Sub(start)
170	
171		result := &Result{
172			Harness:    harness,
173			Model:      model,
174			DurationMS: int(elapsed.Milliseconds()),
175			ToolCalls:  toolCalls,
176		}
177		if routing != nil {
178			result.Provider = routing.Provider
179			if routing.Model != "" {
180				result.Model = routing.Model
181			}
182			if routing.Harness != "" {
183				result.Harness = routing.Harness
184			}
185		}
186		if final != nil {
187			// Normalized final text from the upstream harness (agent-32e8ff5e);
188			// reviewer verdict extraction now parses this instead of raw stream
189			// frames (ddx-7bc0c8d5).
190			result.Output = final.FinalText
191			if final.Usage != nil {
192				// v0.9.1: Usage fields became *int (nullable).
193				if final.Usage.InputTokens != nil {
194					result.InputTokens = *final.Usage.InputTokens
195				}
196				if final.Usage.OutputTokens != nil {
197					result.OutputTokens = *final.Usage.OutputTokens
198				}
199				if final.Usage.TotalTokens != nil {
200					result.Tokens = *final.Usage.TotalTokens
201				}
202			}
203			if final.CostUSD > 0 {
204				result.CostUSD = final.CostUSD
205			}
206			if final.RoutingActual != nil {
207				if result.Provider == "" {
208					result.Provider = final.RoutingActual.Provider
209				}
210				if final.RoutingActual.Model != "" {
211					result.Model = final.RoutingActual.Model
212				}
213			}
214			switch final.Status {
215			case "success", "":
216				// happy path
217			case "stalled":
218				result.ExitCode = 1
219				if final.Error != "" {
220					result.Error = "stalled: " + final.Error
221				} else {
222					result.Error = "stalled"
223				}
224			case "timed_out":
225				result.ExitCode = 1
226				result.Error = fmt.Sprintf("timeout after %v", wall.Round(time.Second))
227			case "cancelled":
228				result.ExitCode = 1
229				result.Error = "cancelled"
230			default:
231				result.ExitCode = 1
232				if final.Error != "" {
233					result.Error = final.Error
234				} else {
235					result.Error = final.Status
236				}
237			}
238			if final.SessionLogPath != "" {
239				result.AgentSessionID = final.SessionLogPath
240			}
241		}
242		entry := SessionIndexEntryFromResult(workDir, SessionIndexInputs{
243			Harness:     harness,
244			Model:       model,
245			Provider:    rcfg.Provider(),
246			Effort:      rcfg.Effort(),
247			Correlation: runtime.Correlation,
248		}, result, start, finishedAt)
249		_ = AppendSessionIndex(ResolveLogDir(workDir, ""), entry, finishedAt)
250		return result, nil
251	}
