276	func ResolveLibraryResource(resourcePath, configPath, workingDir string) (string, error) {
277		// Load config to get the authoritative library path (which includes env var override)
278		cfg, err := LoadWithWorkingDir(workingDir)
279		if err == nil && cfg.Library != nil && cfg.Library.Path != "" {
280			// Check if it's an absolute path
281			if filepath.IsAbs(resourcePath) {
282				return resourcePath, nil
283			}
284	
285			// Try relative to library path from config
286			configPath := filepath.Join(cfg.Library.Path, resourcePath)
287			if _, err := os.Stat(configPath); err == nil {
288				return configPath, nil
289			}
290	
291			// Return the config path even if it doesn't exist (for consistency)
292			return configPath, nil
293		}
294	
295		// Fall back to original logic if config loading fails
296		if workingDir == "" {
297			workingDir, err = os.Getwd()
298			if err != nil {
299				return "", err
300			}
301		}
302	
303		// Check if it's an absolute path
304		if filepath.IsAbs(resourcePath) {
305			return resourcePath, nil
306		}
307	
308		// Try relative to working directory first
309		fullPath := filepath.Join(workingDir, resourcePath)
310		if _, err := os.Stat(fullPath); err == nil {
311			return fullPath, nil
312		}
313	
314		// Try relative to library directory
315		libraryPath := filepath.Join(workingDir, "library", resourcePath)
316		if _, err := os.Stat(libraryPath); err == nil {
317			return libraryPath, nil
318		}
319	
320		// Return the original path even if it doesn't exist
321		return fullPath, nil
322	}
