170	// requireSealed panics if r was not produced by Resolve / LoadAndResolve.
171	// Called as the first statement of every public accessor.
172	func (r ResolvedConfig) requireSealed() {
173		if !r.sealed {
174			panic("config: ResolvedConfig used without going through " +
175				"(*Config).Resolve or config.LoadAndResolve. " +
176				"Production callers must obtain a ResolvedConfig from " +
177				"LoadAndResolve; tests must use NewTestConfigFor*.")
178		}
179	}
